/* ── INLINE CSS ─────────────────────────────────────────── */
const CSS_STYLES = `
  .nav{position:fixed;top:0;width:100%;z-index:1000;padding:20px 64px;display:flex;justify-content:space-between;align-items:center;transition:all .4s;}
  .nav.scrolled{background:rgba(4,4,10,.92);backdrop-filter:blur(24px);border-bottom:1px solid var(--border);}
  .nav-logo{font-family:'Syne',sans-serif;font-size:22px;font-weight:800;letter-spacing:2px;background:linear-gradient(90deg,var(--accent2),var(--cyan));-webkit-background-clip:text;-webkit-text-fill-color:transparent;}
  .nav-links{display:flex;gap:36px;list-style:none;}
  .nav-links a{color:var(--muted);text-decoration:none;font-size:12px;letter-spacing:2px;text-transform:uppercase;transition:color .3s;position:relative;}
  .nav-links a::after{content:'';position:absolute;bottom:-5px;left:0;width:0;height:1px;background:linear-gradient(90deg,var(--accent),var(--cyan));transition:width .35s;}
  .nav-links a:hover{color:var(--cyan);}
  .nav-links a:hover::after{width:100%;}

  .hero{min-height:100vh;position:relative;overflow:hidden;display:flex;align-items:center;justify-content:center;padding:96px 64px 72px;}
  #hero-canvas{position:absolute;inset:0;z-index:0;}
  .hero-grid{position:absolute;inset:0;z-index:0;opacity:.03;background-image:linear-gradient(var(--accent) 1px,transparent 1px),linear-gradient(90deg,var(--accent) 1px,transparent 1px);background-size:60px 60px;}
  .hero-content{position:relative;z-index:2;width:min(100%,1180px);max-width:none;text-align:center;margin:0 auto;}
  .hero-badge{display:inline-flex;align-items:center;justify-content:center;gap:10px;font-size:11px;letter-spacing:3px;text-transform:uppercase;color:var(--green);margin-bottom:24px;max-width:100%;flex-wrap:wrap;}
  .badge-dot{width:6px;height:6px;border-radius:50%;background:var(--green);animation:pulse-g 2s infinite;}
  @keyframes pulse-g{0%,100%{box-shadow:0 0 0 0 rgba(16,185,129,.6)}50%{box-shadow:0 0 0 8px rgba(16,185,129,0)}}
  .hero-name{font-family:'Syne',sans-serif;font-size:clamp(30px,5.2vw,68px);font-weight:800;line-height:1.05;letter-spacing:0;white-space:nowrap;width:100%;max-width:100%;overflow:visible;background:linear-gradient(135deg,#fff 0%,#c4b5fd 45%,var(--cyan) 100%);-webkit-background-clip:text;-webkit-text-fill-color:transparent;}
  .hero-sub{font-family:'JetBrains Mono',monospace;font-size:17px;color:var(--muted);margin-top:28px;min-height:26px;}
  .cursor-blink{display:inline-block;width:2px;height:17px;background:var(--accent2);margin-left:3px;vertical-align:middle;animation:blink 1s step-end infinite;}
  @keyframes blink{0%,100%{opacity:1}50%{opacity:0}}
  .hero-desc{color:var(--muted);font-size:15px;line-height:1.8;margin:20px auto 0;max-width:620px;}
  .hero-cta{display:flex;justify-content:center;gap:16px;margin-top:44px;flex-wrap:wrap;}

  .btn{padding:13px 36px;font-family:'Space Grotesk',sans-serif;font-size:12px;letter-spacing:2px;text-transform:uppercase;cursor:pointer;transition:all .35s;text-decoration:none;display:inline-block;font-weight:600;}
  .btn-primary{background:linear-gradient(135deg,var(--accent),var(--accent2));color:#fff;border:none;box-shadow:0 0 30px rgba(124,58,237,.35);}
  .btn-primary:hover{transform:translateY(-3px);box-shadow:0 12px 40px rgba(124,58,237,.55);}
  .btn-outline{background:transparent;color:var(--text);border:1px solid var(--border2);}
  .btn-outline:hover{border-color:var(--cyan);color:var(--cyan);box-shadow:0 0 24px rgba(34,211,238,.15);transform:translateY(-3px);}
  .btn-resume{display:inline-flex;align-items:center;justify-content:center;gap:10px;background:rgba(34,211,238,.08);color:var(--cyan);border:1px solid rgba(34,211,238,.38);}
  .btn-resume::before{content:"\\2193";font-size:14px;line-height:1;color:var(--cyan);}
  .btn-resume:hover{background:rgba(34,211,238,.14);border-color:var(--cyan);box-shadow:0 0 28px rgba(34,211,238,.18);transform:translateY(-3px);}
  .btn-sm{padding:8px 22px;font-size:11px;letter-spacing:1.5px;}

  section{padding:120px 64px;}
  section.alt-bg{background:var(--bg2);}
  .sec-label{display:flex;align-items:center;gap:12px;font-size:11px;letter-spacing:4px;color:var(--accent2);text-transform:uppercase;margin-bottom:12px;}
  .sec-label::before{content:'';width:30px;height:1px;background:var(--accent2);}
  .sec-title{font-family:'Syne',sans-serif;font-size:clamp(36px,5vw,64px);font-weight:800;line-height:1;margin-bottom:56px;}
  .sec-title span{background:linear-gradient(90deg,var(--accent2),var(--cyan));-webkit-background-clip:text;-webkit-text-fill-color:transparent;}

  /* ── ABOUT ── */
  .about-grid{display:grid;grid-template-columns:380px 1fr;gap:72px;align-items:center;}
  .about-img-wrap{position:relative;}
  .about-photo{width:100%;aspect-ratio:3/4;object-fit:cover;object-position:top;filter:grayscale(15%) contrast(1.05);border:1px solid var(--border2);position:relative;z-index:1;}
  .about-border{position:absolute;width:calc(100% - 20px);height:calc(100% - 20px);border:1px solid var(--accent);bottom:-18px;right:-18px;z-index:0;animation:float 4s ease-in-out infinite;}
  .about-border2{position:absolute;width:60px;height:60px;border:1px solid var(--cyan);top:-14px;left:-14px;z-index:0;animation:float 5s ease-in-out infinite reverse;}
  @keyframes float{0%,100%{transform:translateY(0)}50%{transform:translateY(-10px)}}
  .about-text p{color:var(--muted);line-height:1.9;font-size:15px;margin-bottom:18px;}
  .about-stats{display:grid;grid-template-columns:repeat(3,minmax(120px,1fr));gap:0;max-width:560px;margin-top:44px;}
  .stat{border-left:2px solid var(--accent);min-height:68px;padding:0 22px;display:flex;flex-direction:column;align-items:center;justify-content:center;text-align:center;}
  .stat-num{font-family:'Syne',sans-serif;font-size:44px;font-weight:800;line-height:.95;background:linear-gradient(135deg,var(--accent2),var(--cyan));-webkit-background-clip:text;-webkit-text-fill-color:transparent;}
  .stat-lbl{font-size:11px;color:var(--muted);letter-spacing:1px;margin-top:7px;line-height:1;}

  /* ── SKILLS ── */
  .skills-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:18px;}
  .skill-card{position:relative;isolation:isolate;overflow:hidden;min-height:84px;background:linear-gradient(135deg,rgba(255,255,255,.035),rgba(255,255,255,.012));border:1px solid var(--border);padding:18px 20px;display:flex;align-items:center;gap:16px;transition:border-color .35s,transform .35s cubic-bezier(.23,1,.32,1),box-shadow .35s,background .35s;}
  .skill-card::before{content:'';position:absolute;inset:0;background:radial-gradient(circle at 20% 20%,var(--sk-glow),transparent 34%),linear-gradient(135deg,var(--sk-soft),transparent 54%);opacity:0;transition:opacity .35s;z-index:-1;}
  .skill-card::after{content:'';position:absolute;top:-130%;left:-45%;width:34%;height:360%;background:linear-gradient(90deg,transparent,rgba(255,255,255,.22),transparent);transform:rotate(24deg) translateX(-180%);transition:transform .7s cubic-bezier(.23,1,.32,1);pointer-events:none;}
  .skill-card:hover{border-color:var(--sk);transform:translateY(-8px) scale(1.015);box-shadow:0 18px 42px rgba(0,0,0,.42),0 0 30px var(--sk-glow);background:linear-gradient(135deg,rgba(255,255,255,.055),rgba(255,255,255,.018));}
  .skill-card:hover::before{opacity:.75;}
  .skill-card:hover::after{transform:rotate(24deg) translateX(560%);}
  .sk-icon-wrap{position:relative;width:48px;height:48px;border-radius:12px;border:1px solid rgba(255,255,255,.08);display:flex;align-items:center;justify-content:center;flex-shrink:0;overflow:hidden;transition:transform .35s cubic-bezier(.23,1,.32,1),border-color .35s,box-shadow .35s,background .35s;}
  .sk-icon-wrap::before{content:'';position:absolute;inset:-45%;background:conic-gradient(from 180deg,transparent,var(--sk),transparent 38%);opacity:0;animation:spin-skill 3s linear infinite;transition:opacity .35s;}
  .sk-icon{position:relative;z-index:1;width:29px;height:29px;object-fit:contain;transition:transform .35s,filter .35s;}
  @keyframes spin-skill{to{transform:rotate(360deg)}}
  .skill-card:hover .sk-icon-wrap{transform:rotate(-5deg) scale(1.12);border-color:var(--sk);box-shadow:0 0 24px var(--sk-glow),inset 0 0 18px rgba(255,255,255,.06);background:var(--sk-soft) !important;}
  .skill-card:hover .sk-icon-wrap::before{opacity:.55;}
  .skill-card:hover .sk-icon{transform:scale(1.1) rotate(5deg);filter:drop-shadow(0 0 9px var(--sk-glow));}
  .sk-body{flex:1;min-width:0;}
  .sk-header{display:flex;justify-content:space-between;align-items:baseline;}
  .sk-name{display:block;font-size:13.5px;font-weight:600;transition:color .3s,letter-spacing .3s;}
  .sk-sub{display:block;font-size:11px;color:var(--muted);margin-top:4px;transition:color .3s,transform .3s;}
  .skill-card:hover .sk-name{color:var(--sk);letter-spacing:.4px;}
  .skill-card:hover .sk-sub{color:var(--text);transform:translateY(-1px);}

  /* ── PROJECTS ── */
  .proj-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:28px;}
  .proj-card{position:relative;isolation:isolate;overflow:hidden;min-height:320px;background:linear-gradient(135deg,rgba(255,255,255,.035),rgba(255,255,255,.012));border:1px solid var(--border);transition:all .4s cubic-bezier(.23,1,.32,1);}
  .proj-card::before{content:'';position:absolute;inset:0;background:radial-gradient(circle at 20% 20%,var(--proj-glow),transparent 34%),linear-gradient(135deg,var(--proj-soft),transparent 54%);opacity:0;transition:opacity .35s;z-index:-1;}
  .proj-card::after{content:'';position:absolute;top:0;left:0;right:0;height:2px;background:var(--pc);transform:scaleX(0);transform-origin:left;transition:transform .4s cubic-bezier(.23,1,.32,1);}
  .proj-card:hover{transform:translateY(-10px);border-color:var(--pc);box-shadow:0 28px 60px rgba(0,0,0,.55),0 0 32px var(--proj-glow);background:linear-gradient(135deg,rgba(255,255,255,.05),rgba(255,255,255,.018));}
  .proj-card:hover::before{opacity:.75;}
  .proj-card:hover::after{transform:scaleX(1);}

  /* project image area */
  .proj-visual{width:100%;height:200px;position:relative;overflow:hidden;display:flex;align-items:center;justify-content:center;}
  .proj-visual svg{width:100%;height:100%;transition:transform .5s ease;}
  .proj-card:hover .proj-visual svg{transform:scale(1.04);}

  /* browser chrome bar */
  .proj-chrome{position:absolute;top:0;left:0;right:0;height:28px;background:rgba(0,0,0,.35);display:flex;align-items:center;padding:0 12px;gap:6px;z-index:2;}
  .proj-chrome span{width:8px;height:8px;border-radius:50%;}

  .proj-body{padding:24px 26px 22px;}
  .proj-num{font-family:'Syne',sans-serif;font-size:48px;font-weight:800;color:rgba(255,255,255,.04);line-height:1;margin-bottom:8px;transition:color .4s;}
  .proj-card:hover .proj-num{color:rgba(124,58,237,.14);}
  .proj-title{font-family:'Syne',sans-serif;font-size:19px;font-weight:700;margin-bottom:4px;}
  .proj-subtitle{font-size:11px;color:var(--accent2);letter-spacing:1.5px;text-transform:uppercase;margin-bottom:12px;}
  .proj-desc{font-size:13px;color:var(--muted);line-height:1.85;margin-bottom:16px;}
  .proj-tags{display:flex;flex-wrap:wrap;gap:7px;margin-bottom:16px;}
  .proj-tag{padding:4px 11px;border:1px solid var(--border);font-size:10.5px;letter-spacing:.8px;color:var(--muted);transition:all .3s;}
  .proj-card:hover .proj-tag{border-color:rgba(124,58,237,.4);color:var(--accent2);}
  .proj-footer{display:flex;align-items:center;justify-content:space-between;}
  .proj-live{font-size:11px;letter-spacing:2px;color:var(--cyan);text-transform:uppercase;text-decoration:none;display:inline-flex;align-items:center;gap:6px;transition:gap .3s;}
  .proj-live:hover{gap:12px;}

  /* ── INTERNSHIPS ── */
  .intern-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:24px;}
  .intern-card{position:relative;isolation:isolate;overflow:hidden;min-height:260px;background:linear-gradient(135deg,rgba(255,255,255,.035),rgba(255,255,255,.012));border:1px solid var(--border);display:flex;flex-direction:column;transition:all .4s cubic-bezier(.23,1,.32,1);}
  .intern-card::before{content:'';position:absolute;inset:0;background:radial-gradient(circle at 22% 18%,var(--intern-glow),transparent 32%),linear-gradient(135deg,var(--intern-soft),transparent 54%);opacity:0;transition:opacity .35s;z-index:-1;}
  .intern-card::after{content:'';position:absolute;top:-130%;left:-45%;width:34%;height:360%;background:linear-gradient(90deg,transparent,rgba(255,255,255,.22),transparent);transform:rotate(24deg) translateX(-180%);transition:transform .7s cubic-bezier(.23,1,.32,1);pointer-events:none;}
  .intern-card:hover{transform:translateY(-8px);box-shadow:0 20px 50px rgba(0,0,0,.5),0 0 30px var(--intern-glow);background:linear-gradient(135deg,rgba(255,255,255,.05),rgba(255,255,255,.018));border-color:var(--int-color);}
  .intern-card:hover::before{opacity:.7;}
  .intern-card:hover::after{transform:rotate(24deg) translateX(560%);}
  .intern-logo-box{position:relative;z-index:1;flex-shrink:0;width:64px;height:64px;border-radius:14px;display:flex;align-items:center;justify-content:center;transition:transform .35s,box-shadow .35s;}
  .intern-card:hover .intern-logo-box{transform:scale(1.05);box-shadow:0 0 24px var(--intern-glow);}
  .intern-card:hover .intern-company{color:var(--int-color);}
  .intern-card:hover .intern-tag{border-color:var(--int-color);color:var(--int-color);}
  .intern-logo-box svg{width:100%;height:100%;}
  .intern-title-col{flex:1;display:flex;flex-direction:column;gap:6px;}
  .intern-company{font-family:'Syne',sans-serif;font-size:19px;font-weight:700;margin-bottom:0;}
  .intern-role{font-size:13px;color:var(--muted);line-height:1.5;margin-bottom:0;}
  .intern-period{font-size:11px;letter-spacing:2px;text-transform:uppercase;color:var(--accent2);}
  .intern-header{padding:28px 28px 20px;display:flex;align-items:center;gap:20px;}
  .intern-body{padding:0 28px 24px;display:flex;flex-direction:column;gap:16px;}
  .intern-desc{font-size:13px;color:var(--muted);line-height:1.8;margin:0;}
  .intern-tags{display:flex;flex-wrap:wrap;gap:7px;}
  .intern-tag{padding:4px 12px;border:1px solid var(--border);font-size:11px;color:var(--muted);border-radius:2px;}
  .intern-divider{height:3px;width:100%;margin-top:auto;}

  /* ── CERTIFICATES ── */
  .certs-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:22px;}
  .cert-card{border:1px solid var(--border);overflow:hidden;transition:border-color .35s,transform .35s cubic-bezier(.23,1,.32,1),box-shadow .35s,background .35s;cursor:pointer;position:relative;isolation:isolate;}
  .cert-card::before{content:'';position:absolute;inset:0;background:radial-gradient(circle at 20% 20%,var(--cert-glow),transparent 34%),linear-gradient(135deg,var(--cert-soft),transparent 54%);opacity:0;transition:opacity .35s;z-index:-1;}
  .cert-card::after{content:'';position:absolute;top:-130%;left:-45%;width:34%;height:360%;background:linear-gradient(90deg,transparent,rgba(255,255,255,.22),transparent);transform:rotate(24deg) translateX(-180%);transition:transform .7s cubic-bezier(.23,1,.32,1);pointer-events:none;}
  .cert-card:hover{border-color:var(--cert-glow);transform:translateY(-8px) scale(1.015);box-shadow:0 18px 42px rgba(0,0,0,.42),0 0 30px var(--cert-glow);background:linear-gradient(135deg,rgba(255,255,255,.055),rgba(255,255,255,.018));}
  .cert-card:hover::before{opacity:.75;}
  .cert-card:hover::after{transform:rotate(24deg) translateX(560%);}
  /* visual certificate top */
  .cert-visual{height:130px;position:relative;display:flex;flex-direction:column;align-items:center;justify-content:center;padding:16px;}
  .cert-watermark{position:absolute;inset:0;display:flex;align-items:center;justify-content:center;font-size:80px;opacity:.07;pointer-events:none;user-select:none;}
  .cert-year-badge{margin-top:8px;font-size:10px;letter-spacing:3px;text-transform:uppercase;opacity:.8;font-family:'JetBrains Mono',monospace;z-index:1;}
  /* cert body */
  .cert-body{background:var(--bg3);padding:16px 18px 18px;}
  .cert-issuer-row{display:flex;align-items:center;gap:8px;margin-bottom:8px;}
  .cert-issuer-dot{width:6px;height:6px;border-radius:50%;flex-shrink:0;}
  .cert-issuer-name{font-size:10.5px;letter-spacing:1.5px;text-transform:uppercase;color:var(--muted);}
  .cert-type-label{font-size:10px;color:var(--accent2);letter-spacing:1px;text-transform:uppercase;margin-bottom:6px;}
  .cert-title{font-size:13px;font-weight:600;line-height:1.45;color:var(--text);margin-bottom:12px;}
  .cert-skills{display:flex;flex-wrap:wrap;gap:5px;margin-bottom:12px;}
  .cert-skill{padding:2px 8px;font-size:10px;letter-spacing:.5px;border:1px solid;border-radius:2px;opacity:.7;}
  .cert-actions{display:flex;gap:8px;}
  .cert-btn{flex:1;padding:7px 0;font-family:'Space Grotesk',sans-serif;font-size:10px;letter-spacing:1.5px;text-transform:uppercase;cursor:pointer;text-align:center;transition:all .3s;text-decoration:none;display:flex;align-items:center;justify-content:center;gap:5px;border:none;}
  .cert-btn-view{color:#fff;}
  .cert-btn-pdf{background:transparent;color:var(--muted);border:1px solid var(--border) !important;}
  .cert-btn-pdf:hover{border-color:var(--accent2) !important;color:var(--accent2);}

  /* cert modal */
  .cert-modal-overlay{position:fixed;inset:0;background:rgba(0,0,0,.85);z-index:9990;display:flex;align-items:center;justify-content:center;padding:24px;backdrop-filter:blur(8px);}
  .cert-modal{background:var(--bg2);border:1px solid var(--border2);max-width:640px;width:100%;max-height:85vh;overflow:auto;position:relative;}
  .cert-modal-close{position:absolute;top:16px;right:16px;background:rgba(255,255,255,.08);border:none;color:var(--text);width:32px;height:32px;cursor:pointer;font-size:18px;display:flex;align-items:center;justify-content:center;}
  .cert-modal-top{height:200px;position:relative;display:flex;align-items:center;justify-content:center;}
  .cert-modal-body{padding:28px;}
  .cert-modal-title{font-family:'Syne',sans-serif;font-size:22px;font-weight:700;margin-bottom:8px;}
  .cert-modal-meta{font-size:13px;color:var(--muted);margin-bottom:20px;line-height:1.7;}
  .cert-modal-preview{margin-bottom:24px;border:1px solid var(--border2);border-radius:12px;overflow:hidden;background:var(--bg3);}
  .cert-modal-skills{display:flex;flex-wrap:wrap;gap:8px;margin-bottom:24px;}
  .cert-modal-skill{padding:5px 14px;border:1px solid var(--border2);font-size:12px;color:var(--muted);}
  .cert-modal-actions{display:flex;gap:12px;}

  /* CONTACT */
  .contact-grid{display:grid;grid-template-columns:1fr 1fr;gap:72px;align-items:start;justify-items:start;}
  .contact-left{display:flex;flex-direction:column;}
  .contact-right{display:flex;flex-direction:column;}
  .contact-desc{font-size:15px;color:var(--muted);line-height:1.9;margin-bottom:36px;}
  .contact-links{display:grid;grid-template-columns:1fr 1fr;gap:14px;}
  .contact-link{position:relative;display:flex;align-items:center;gap:16px;color:var(--text);text-decoration:none;font-size:14px;padding:16px 20px;border:1px solid var(--border);border-radius:14px;background:linear-gradient(135deg,rgba(255,255,255,.035),rgba(255,255,255,.01));overflow:hidden;transition:transform .35s,border-color .35s,color .35s,box-shadow .35s,background .35s;}
  .contact-link::before{content:'';position:absolute;inset:0;background:radial-gradient(circle at 20% 20%,rgba(56,189,248,.24),transparent 32%),linear-gradient(135deg,rgba(255,255,255,.12),transparent 54%);opacity:0;transition:opacity .35s;z-index:-1;}
  .contact-link:hover{border-color:var(--accent2);color:var(--accent2);transform:translateX(8px);box-shadow:0 24px 50px rgba(0,0,0,.16);}
  .contact-link:hover::before{opacity:.65;}
  .contact-link-icon{width:24px;display:flex;align-items:center;justify-content:center;}
  .contact-link-icon svg,.contact-link-icon img{width:20px;height:20px;display:block;}
  .contact-form{display:flex;flex-direction:column;gap:14px;width:100%;}
  .contact-form input,.contact-form textarea{background:var(--glass);border:1px solid var(--border);padding:14px 18px;color:var(--text);font-family:'Space Grotesk',sans-serif;font-size:14px;outline:none;transition:border-color .3s;border-radius:8px;width:100%;box-sizing:border-box;}
  .contact-form input:focus,.contact-form textarea:focus{border-color:var(--accent);}
  .contact-form input:disabled,.contact-form textarea:disabled{opacity:0.6;cursor:not-allowed;}
  .contact-form textarea{flex:1;min-height:150px;max-height:220px;resize:none;padding:14px 18px;}
  .contact-form-message{font-size:13px;padding:12px;border-radius:8px;text-align:center;}
  .contact-form-message.success{background:rgba(16,185,129,.1);color:#10b981;border:1px solid rgba(16,185,129,.3);}
  .contact-form-message.error{background:rgba(239,68,68,.1);color:#ef4444;border:1px solid rgba(239,68,68,.3);}
  .contact-form button{transition:all .3s;}
  .contact-form button:disabled{opacity:0.7;cursor:not-allowed;}

  footer{padding:32px 64px;border-top:1px solid var(--border);display:flex;justify-content:space-between;align-items:center;font-size:12px;color:var(--muted);letter-spacing:1px;}
  .reveal{opacity:0;transform:translateY(32px);transition:opacity .8s,transform .8s;}
  .reveal.visible{opacity:1;transform:translateY(0);}
  .noise{position:fixed;inset:0;z-index:9990;pointer-events:none;opacity:.018;background-image:url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)'/%3E%3C/svg%3E");background-size:256px 256px;}
  .orb{position:absolute;border-radius:50%;filter:blur(80px);pointer-events:none;z-index:0;}
  .orb1{width:500px;height:500px;background:rgba(124,58,237,.12);top:-100px;right:-100px;}
  .orb2{width:400px;height:400px;background:rgba(34,211,238,.08);bottom:10%;left:-80px;}
  @media(max-width:900px){
    section{padding:72px 24px;}
    .nav{padding:16px 24px;}.nav-links{gap:20px;}
    .hero{padding:100px 24px 72px;}
    .hero-name{font-size:clamp(30px,7vw,48px);}
    .about-grid,.contact-grid{grid-template-columns:1fr;gap:40px;}
    .about-stats{max-width:100%;}
    .proj-grid,.skills-grid,.intern-grid,.certs-grid{grid-template-columns:1fr;}
    footer{flex-direction:column;gap:8px;}
    .contact-form-message{font-size:12px;padding:10px;}
  }
  @media(max-width:768px){
    section{padding:56px 20px;}
    .sec-title{font-size:clamp(28px,6vw,40px);margin-bottom:40px;}
    .hero{padding:80px 20px 60px;}
    .hero-desc{font-size:14px;}
    .hero-cta{gap:12px;margin-top:32px;}
    .btn{padding:11px 28px;font-size:11px;}
    .contact-form input,.contact-form textarea{padding:12px 16px;font-size:13px;}
    .contact-form textarea{min-height:120px;max-height:180px;}
    .proj-card,.skill-card,.cert-card,.intern-card{border-radius:10px;}
    .contact-link{padding:14px 16px;font-size:13px;gap:12px;}
  }
  @media(max-width:520px){
    section{padding:40px 16px;}
    .hero-name{font-size:clamp(24px,6vw,32px);}
    .hero-badge{font-size:10px;letter-spacing:2px;}
    .hero-desc{font-size:13px;line-height:1.6;max-width:100%;}
    .hero-cta{flex-direction:column;gap:10px;margin-top:24px;}
    .btn{width:100%;padding:10px 20px;font-size:10px;letter-spacing:1px;}
    .about-stats{grid-template-columns:1fr;gap:18px;}
    .stat{border-left:0;border-top:2px solid var(--accent);padding:16px 0;}
    .sec-title{font-size:clamp(20px,5vw,28px);margin-bottom:28px;}
    .sec-label{font-size:11px;letter-spacing:3px;}
    .contact-form{gap:12px;}
    .contact-form input,.contact-form textarea{padding:11px 14px;font-size:13px;border-radius:6px;}
    .contact-form textarea{min-height:100px;max-height:160px;}
    .contact-link{flex-direction:column;text-align:center;padding:12px 14px;font-size:12px;height:auto;}
    .contact-link-icon{width:20px;}
    .contact-link-icon svg,.contact-link-icon img{width:16px;height:16px;}
    .contact-links{grid-template-columns:1fr;}
    .cert-card{border-radius:8px;padding:12px;}
    .proj-card{border-radius:8px;}
    .skill-card{border-radius:8px;}
    footer{font-size:12px;gap:12px;padding:0 16px;}
  }
  @media(max-width:380px){
    section{padding:32px 12px;}
    .hero{padding:60px 12px 48px;}
    .hero-name{font-size:clamp(20px,6vw,26px);}
    .hero-badge{font-size:9px;padding:6px 12px;}
    .btn{padding:9px 16px;font-size:9px;}
    .sec-title{font-size:clamp(18px,5vw,24px);margin-bottom:20px;}
    .contact-form input,.contact-form textarea{padding:10px 12px;font-size:12px;}
    .contact-form textarea{min-height:90px;}
    .contact-form-message{font-size:11px;padding:8px;}
    .about-photo{aspect-ratio:3/4;}
    .nav-logo{font-size:14px;}
    footer{font-size:11px;}
  }
`;

