export default function Portfolio() {
  const [typed,    setTyped]    = useState("");
  const [scrolled, setScrolled] = useState(false);
  const [form,     setForm]     = useState({ name:"", email:"", msg:"" });
  const [activeCert, setActiveCert] = useState<typeof CERTS[0] | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitMessage, setSubmitMessage] = useState<{type: 'success' | 'error', text: string} | null>(null);

  const canvasRef   = useRef<HTMLCanvasElement>(null);
  const dotRef      = useRef<HTMLDivElement>(null);
  const ringRef     = useRef<HTMLDivElement>(null);

  /* inject CSS */
  useEffect(() => {
    const s = document.createElement("style"); s.textContent = CSS_STYLES;
    document.head.appendChild(s); return () => { document.head.removeChild(s); };
  }, []);

  /* Initialize EmailJS */
  useEffect(() => {
    emailjs.init(import.meta.env.VITE_EMAILJS_PUBLIC_KEY);
  }, []);

  /* typewriter */
  useEffect(() => {
    const phrases = ["Full Stack Developer","Python & Django Developer","IoT Enthusiast","UI/UX Enthusiast"];
    let pi=0,ci=0,del=false,t:ReturnType<typeof setTimeout>;
    const tick=()=>{
      const c=phrases[pi];
      if(!del){setTyped(c.slice(0,ci+1));ci++;if(ci===c.length){del=true;t=setTimeout(tick,1800);return;}}
      else{setTyped(c.slice(0,ci-1));ci--;if(ci===0){del=false;pi=(pi+1)%phrases.length;}}
      t=setTimeout(tick,del?55:95);
    };
    t=setTimeout(tick,600); return ()=>clearTimeout(t);
  },[]);

  /* particle canvas */
  useEffect(() => {
    const cv=canvasRef.current; if(!cv) return;
    const ctx=cv.getContext("2d")!;
    let W=cv.width=window.innerWidth, H=cv.height=window.innerHeight;
    const pts=Array.from({length:80},()=>({x:Math.random()*W,y:Math.random()*H,vx:(Math.random()-.5)*.35,vy:(Math.random()-.5)*.35,r:Math.random()*1.5+.3,a:Math.random()*.4+.08}));
    let mx=-999,my=-999;
    const mm=(e:MouseEvent)=>{mx=e.clientX;my=e.clientY;};
    window.addEventListener("mousemove",mm);
    let raf:number;
    const draw=()=>{
      ctx.clearRect(0,0,W,H);
      pts.forEach((p,i)=>{
        const dx=p.x-mx,dy=p.y-my,d=Math.hypot(dx,dy);
        if(d<110){p.vx+=dx/d*.35;p.vy+=dy/d*.35;}
        p.vx*=.993;p.vy*=.993;
        p.x=(p.x+p.vx+W)%W;p.y=(p.y+p.vy+H)%H;
        ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,Math.PI*2);
        ctx.fillStyle=`rgba(168,85,247,${p.a})`;ctx.fill();
        for(let j=i+1;j<pts.length;j++){
          const q=pts[j],dd=Math.hypot(p.x-q.x,p.y-q.y);
          if(dd<120){ctx.beginPath();ctx.moveTo(p.x,p.y);ctx.lineTo(q.x,q.y);ctx.strokeStyle=`rgba(124,58,237,${.1*(1-dd/120)})`;ctx.lineWidth=.5;ctx.stroke();}
        }
      });
      raf=requestAnimationFrame(draw);
    };
    draw();
    const rz=()=>{W=cv.width=window.innerWidth;H=cv.height=window.innerHeight;};
    window.addEventListener("resize",rz);
    return ()=>{cancelAnimationFrame(raf);window.removeEventListener("mousemove",mm);window.removeEventListener("resize",rz);};
  },[]);

  /* custom cursor */
  useEffect(() => {
    let fx=window.innerWidth/2,fy=window.innerHeight/2,mx=fx,my=fy,raf:number;
    const interactive='a,button,[role="button"],input,textarea,select,.cert-card,.proj-card,.skill-card,.contact-link';
    const setHover=(target:EventTarget|null)=>{
      document.body.classList.toggle("cursor-hover",target instanceof Element && Boolean(target.closest(interactive)));
    };
    const mm=(e:MouseEvent)=>{
      mx=e.clientX;my=e.clientY;
      document.body.classList.remove("cursor-away");
      setHover(e.target);
      if(dotRef.current){dotRef.current.style.left=mx+"px";dotRef.current.style.top=my+"px";}
    };
    const down=()=>document.body.classList.add("cursor-pressed");
    const up=()=>document.body.classList.remove("cursor-pressed");
    const leave=()=>document.body.classList.add("cursor-away");
    const enter=()=>document.body.classList.remove("cursor-away");
    const anim=()=>{
      fx+=(mx-fx)*.16;fy+=(my-fy)*.16;
      if(ringRef.current){ringRef.current.style.left=fx+"px";ringRef.current.style.top=fy+"px";}
      raf=requestAnimationFrame(anim);
    };
    anim();document.addEventListener("mousemove",mm);document.addEventListener("mousedown",down);document.addEventListener("mouseup",up);document.addEventListener("mouseleave",leave);document.addEventListener("mouseenter",enter);
    return ()=>{document.removeEventListener("mousemove",mm);document.removeEventListener("mousedown",down);document.removeEventListener("mouseup",up);document.removeEventListener("mouseleave",leave);document.removeEventListener("mouseenter",enter);document.body.classList.remove("cursor-hover","cursor-pressed","cursor-away");cancelAnimationFrame(raf);};
  },[]);

  /* scroll */
  useEffect(() => {
    const h=()=>setScrolled(window.scrollY>40);
    window.addEventListener("scroll",h); return ()=>window.removeEventListener("scroll",h);
  },[]);

  /* reveal on scroll */
  useEffect(() => {
    const io=new IntersectionObserver(es=>es.forEach(e=>{if(e.isIntersecting)e.target.classList.add("visible");}),{threshold:.12});
    document.querySelectorAll(".reveal").forEach(el=>io.observe(el));
    return ()=>io.disconnect();
  },[]);

  /* Handle form submission */
  const handleSubmit = async () => {
    if (!form.name || !form.email || !form.msg) {
      setSubmitMessage({ type: 'error', text: 'Please fill in all fields' });
      return;
    }

    setIsSubmitting(true);
    setSubmitMessage(null);

    try {
      await emailjs.send(
        import.meta.env.VITE_EMAILJS_SERVICE_ID || "",
        import.meta.env.VITE_EMAILJS_TEMPLATE_ID || "",
        {
          to_email: import.meta.env.VITE_CONTACT_EMAIL,
          from_name: form.name,
          from_email: form.email,
          message: form.msg,
        }
      );
      
      setSubmitMessage({ type: 'success', text: 'Message sent successfully! I\'ll get back to you soon.' });
      setForm({ name: "", email: "", msg: "" });
    } catch (error) {
      console.error("Email send error:", error);
      setSubmitMessage({ type: 'error', text: 'Failed to send message. Please try again later.' });
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <>
      <div className="noise" aria-hidden/>
      <div id="cur-dot"  ref={dotRef}  aria-hidden/>
      <div id="cur-ring" ref={ringRef} aria-hidden/>

      {/* ── NAV ── */}
      <nav className={`nav${scrolled?" scrolled":""}`}>
        <div className="nav-logo">PORTFOLIO</div>
        <ul className="nav-links">
          {["About","Skills","Projects","Experience","Contact"].map(l=>(
            <li key={l}><a href={`#${l.toLowerCase()}`}>{l}</a></li>
          ))}
        </ul>
      </nav>

      {/* ── HERO ── */}
      <section id="home" className="hero">
        <canvas ref={canvasRef} id="hero-canvas"/>
        <div className="hero-grid" aria-hidden/>
        <div className="orb orb1"/><div className="orb orb2"/>
        <div className="hero-content">
          <div className="hero-badge"><div className="badge-dot"/>B.E Computer Science and Engineering - Fresher</div>
          <h1 className="hero-name">TAMIZHSELVAN A</h1>
          <p className="hero-sub">{typed}<span className="cursor-blink" aria-hidden/></p>
          <p className="hero-desc">Computer Science engineer with hands-on experience in full-stack development, IoT systems, and computer vision. Building real-world solutions.</p>
          <div className="hero-cta">
            <a href="#projects" className="btn btn-primary">View Projects</a>
            <a href="#contact" className="btn btn-outline">Get In Touch</a>
            <button type="button" className="btn btn-resume" onClick={() => downloadFile(resumePDF, "Resume.pdf")}>Download Resume</button>
          </div>
        </div>
      </section>

      {/* ── ABOUT ── */}
      <section id="about">
        <div className="sec-label">Who I Am</div>
        <div className="sec-title reveal">About <span>Me</span></div>
        <div className="about-grid">
          <div className="about-img-wrap reveal">
            <img className="about-photo" src={PHOTO} alt="Tamizhselvan A"/>
            <div className="about-border" aria-hidden/><div className="about-border2" aria-hidden/>
          </div>
          <div className="reveal">
            <div className="about-text">
              <p>Hi, I'm <strong style={{color:"var(--accent2)"}}>Tamizhselvan A</strong> — a Computer Science &amp; Engineering student at Annai Vailankanni College of Engineering, Kanyakumari (CGPA 7.8, 2022–2026).</p>
              <p>Strong foundation in full-stack development, computer vision and mobile apps. Skilled in Python (Django), ReactNative, Node.js, PostgreSQL and OpenCV.</p>
              <p>Completed internships at IPCS Global and Wizbees Technologies with real-world project contributions. Holding 6+ professional certifications.</p>
            </div>
            <div className="about-stats">
              {([["7.8","CGPA"],["2","Internships"],["6+","Certifications"]] as [string,string][]).map(([n,l])=>(
                <div className="stat" key={l}><div className="stat-num">{n}</div><div className="stat-lbl">{l}</div></div>
              ))}
            </div>
          </div>
        </div>
      </section>

      {/* ── SKILLS ── */}
      <section id="skills" className="alt-bg">
        <div className="sec-label">What I Know</div>
        <div className="sec-title reveal">Technical <span>Skills</span></div>
        <div className="skills-grid">
          {SKILLS.map((sk,i)=>(
            <div
              className="skill-card reveal"
              key={sk.name}
              style={{
                "--sk": sk.color,
                "--sk-glow": `${sk.color}66`,
                "--sk-soft": `${sk.color}18`,
                transitionDelay: `${i*.05}s`,
              } as React.CSSProperties}
            >
              <div className="sk-icon-wrap" style={{background:`${sk.color}20`}}>
                <img className="sk-icon" src={sk.icon} alt={sk.name}
                  onError={e=>{(e.currentTarget as HTMLImageElement).style.opacity="0";}}/>
              </div>
              <div className="sk-body">
                <div className="sk-header">
                  <div>
                    <span className="sk-name">{sk.name}</span>
                    {sk.sub && <span className="sk-sub">{sk.sub}</span>}
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* ── PROJECTS ── */}
      <section id="projects">
        <div className="sec-label">What I've Built</div>
        <div className="sec-title reveal">Featured <span>Projects</span></div>
        <div className="proj-grid">
          {PROJECTS.map((p,i)=>(
            <div key={p.num} className="proj-card reveal"
              style={{"--pc":p.color, "--proj-glow":`${p.color}66`, "--proj-soft":`${p.color}18`, transitionDelay:`${i*.1}s`} as React.CSSProperties}>
              {/* image area */}
              <div className="proj-visual">
                <div className="proj-chrome">
                  <span style={{background:"#ef4444"}}/>
                  <span style={{background:"#f59e0b"}}/>
                  <span style={{background:"#10b981"}}/>
                </div>
                {p.num==="01" ? <ProjVisual01/> : <ProjVisual02/>}
              </div>
              <div className="proj-body">
                <div className="proj-num">{p.num}</div>
                <div className="proj-title">{p.title}</div>
                <div className="proj-subtitle">{p.subtitle}</div>
                <p className="proj-desc">{p.desc}</p>
                <div className="proj-tags">{p.tags.map(t=><span key={t} className="proj-tag">{t}</span>)}</div>
                <div className="proj-footer">
                  {p.live
                    ? <a href={p.live} target="_blank" rel="noreferrer" className="proj-live">View Live →</a>
                    : <span style={{fontSize:12,color:"var(--muted)",letterSpacing:"1px"}}>IoT Hardware Project</span>
                  }
                  <span style={{fontSize:11,color:"var(--muted)"}}>#{p.num}</span>
                </div>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* ── INTERNSHIPS ── */}
      <section id="experience" className="alt-bg">
        <div className="sec-label">Work Experience</div>
        <div className="sec-title reveal">Internship <span>Experience</span></div>
        <div className="intern-grid">
          {INTERNSHIPS.map((it,i)=>(
            <div key={it.company} className="intern-card reveal"
              style={{borderColor:`${it.color}22`, "--int-color":it.color, "--intern-glow":`${it.color}66`, "--intern-soft":`${it.color}18`, transitionDelay:`${i*.1}s`} as React.CSSProperties}>
              <div className="intern-header">
                <div className="intern-logo-box" style={{background:`${it.color}15`}}>
                  {it.company==="IPCS Global"
                    ? <IPCSLogo/>
                    : <WizbeesLogo/>
                  }
                </div>
                <div className="intern-title-col">
                  <div className="intern-company" style={{color:it.color}}>{it.company}</div>
                  <div className="intern-role">{it.role}</div>
                  <div className="intern-period">{it.period}</div>
                </div>
              </div>
              <div className="intern-body">
                <p className="intern-desc">{it.desc}</p>
                <div className="intern-tags">
                  {it.tech.map(t=>(
                    <span key={t} className="intern-tag" style={{borderColor:`${it.color}40`,color:it.color}}>{t}</span>
                  ))}
                </div>
              </div>
              <div className="intern-divider" style={{background:`linear-gradient(90deg,${it.color}60,transparent)`}}/>
            </div>
          ))}
        </div>

        {/* ── CERTIFICATES ── */}
        <div className="sec-label" style={{marginTop:72}}>Achievements</div>
        <div className="sec-title reveal" style={{marginBottom:36}}>
          Certifications <span>&amp; Awards</span>
        </div>
        <p className="reveal" style={{color:"var(--muted)",fontSize:14,marginBottom:36,maxWidth:560}}>
          Click any certificate to preview its details.
        </p>
        <div className="certs-grid">
          {CERTS.map((c,i)=>(
            <div key={c.id} className="cert-card reveal"
              style={{
                "--cert-glow": `${c.color}66`,
                "--cert-soft": `${c.color}18`,
                transitionDelay: `${i*.07}s`,
              } as React.CSSProperties}
              onClick={()=>setActiveCert(c)}>
              {/* visual top — shows actual certificate image */}
              <div className="cert-visual" style={{background:c.bg, padding:0, overflow:"hidden", position:"relative"}}>
                {c.img ? (
                  <img
                    src={c.img}
                    alt={`${c.title} preview`}
                    style={{width:"100%",height:"100%",objectFit:"cover",display:"block",borderRadius:"inherit"}}
                    onError={e=>{
                      const el = e.currentTarget as HTMLImageElement;
                      el.style.display = "none";
                      const fb = el.nextElementSibling as HTMLElement;
                      if(fb) fb.style.display = "flex";
                    }}
                  />
                ) : null}
                {/* fallback shown when image fails or is missing */}
                <div style={{
                  display: c.img ? "none" : "flex",
                  position:"absolute", inset:0,
                  flexDirection:"column", alignItems:"center", justifyContent:"center",
                  gap:6, color:"rgba(255,255,255,0.25)", fontSize:11, letterSpacing:2
                }}>
                  <span style={{fontSize:28,opacity:.4}}>🖼</span>
                  <span>NO IMAGE</span>
                </div>
                <div className="cert-year-badge" style={{color:c.badgeColor, position:"absolute", bottom:8, right:10}}>{c.year}</div>
              </div>
              {/* body */}
              <div className="cert-body">
                <div className="cert-issuer-row">
                  <div className="cert-issuer-dot" style={{background:c.color}}/>
                  <span className="cert-issuer-name">{c.issuer}</span>
                </div>
                <div className="cert-type-label">{c.type}</div>
                <div className="cert-title">{c.title}</div>
                <div className="cert-skills">
                  {c.skills.map(s=>(
                    <span key={s} className="cert-skill" style={{borderColor:`${c.color}50`,color:c.color}}>{s}</span>
                  ))}
                </div>
                <div className="cert-actions">
                  <button className="cert-btn cert-btn-view" style={{background:c.color}}
                    onClick={e=>{e.stopPropagation();setActiveCert(c);}}>
                    👁 Preview
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* ── CERT MODAL ── */}
      {activeCert && <CertModal cert={activeCert} onClose={()=>setActiveCert(null)}/>}

      {/* ── CONTACT ── */}
      <section id="contact">
        <div className="sec-label">Let's Connect</div>
        <div className="sec-title reveal">Get In <span>Touch</span></div>
        <div className="contact-grid">
          <div className="reveal contact-left">
            <p className="contact-desc">I'm actively seeking entry-level opportunities to contribute to a forward-thinking organisation. Whether you have a role or just want to connect — my inbox is open.</p>
            <div className="contact-links">
              {[{
                  icon:`${DI}/google/google-original.svg`,
                  label:"tamilselvan2702@gmail.com",
                  href:"mailto:tamilselvan2702@gmail.com",
                  external:true,
                },{
                  icon:`${DI}/linkedin/linkedin-original.svg`,
                  label:"LinkedIn Profile",
                  href:"https://www.linkedin.com/in/tamizhselvan2702",
                  external:true,
                },{
                  icon:`${DI}/github/github-original.svg`,
                  label:"GitHub Profile",
                  href:"https://github.com/TAMIZHSELVAN-001",
                  external:true,
                }].map(l=>(
                <a key={l.label} href={l.href} target={l.external ? "_blank" : undefined} rel={l.external ? "noreferrer" : undefined} className="contact-link">
                  <span className="contact-link-icon"><img src={l.icon} alt={l.label} onError={e=>{(e.currentTarget as HTMLImageElement).style.opacity="0";}}/></span><span>{l.label}</span>
                </a>
              ))}
            </div>
          </div>
          <div className="contact-form reveal contact-right">
            <input type="text" placeholder="Your Name" value={form.name} onChange={e=>setForm(f=>({...f,name:e.target.value}))} disabled={isSubmitting}/>
            <input type="email" placeholder="Your Email" value={form.email} onChange={e=>setForm(f=>({...f,email:e.target.value}))} disabled={isSubmitting}/>
            <textarea placeholder="Your Message" value={form.msg} onChange={e=>setForm(f=>({...f,msg:e.target.value}))} disabled={isSubmitting}/>
            {submitMessage && (
              <div className={`contact-form-message ${submitMessage.type}`}>
                {submitMessage.text}
              </div>
            )}
            <button className="btn btn-primary" style={{width:"100%"}} onClick={handleSubmit} disabled={isSubmitting}>
              {isSubmitting ? "Sending..." : "Send Message →"}
            </button>
          </div>
        </div>
      </section>

      {/* ── FOOTER ── */}
      <footer>
        <span>© {new Date().getFullYear()} Tamizhselvan A — CSE Engineer, Tirunelveli,Tamil Nadu</span>
        <span style={{color:"var(--accent2)"}}>Open to opportunities</span>
      </footer>
    </>
  );
}